mapper.select:
SELECT DISTINCT m.menu_id AS menu_id,m.parent_id,m.app_type,m.name,url,m.type,m.icon,m.order_num FROM tz_sys_user_role ur LEFT JOIN tz_sys_role_menu rm ON ur.role_id = rm.role_id LEFT JOIN tz_sys_menu m ON m.`menu_id` = rm.`menu_id` WHERE ur.user_id = #{userId} and m.type != 2
AND app_type=#{appType}
order by order_num

select * from tz_sys_menu where `type` != 2

	AND  app_type=#{appType}

order by order_num

select menu_id ,parent_id ,`name` from tz_sys_menu where `type` != 2


	AND  app_type=#{appType}


order by order_num

select * from tz_sys_menu where 1=1
AND app_type=#{appType}
order by order_num

SELECT DISTINCT m.menu_id AS menu_id,m.parent_id,m.app_type,m.name,url,m.type,m.icon,m.order_num FROM tz_sys_menu m where 1=1
AND app_type=#{appType}
and m.menu_id in
	#{item}
